  </footer>

  <script>
    // Global demo API
    window.demo = {
      canvas: document.getElementById('coin-hero'),
      setTime: function(t) {},
      pause: function() {}
    };

    // Helper functions for procedural rendering
    function drawReededEdge(ctx, centerX, centerY, radius, thickness, reedCount) {
      ctx.beginPath();

      const step = (Math.PI * 2) / reedCount;
      for (let i = 0; i < reedCount; i++) {
        const angle1 = i * step;
        const angle2 = (i + 0.5) * step;

        // Ridge
        ctx.moveTo(
          centerX + Math.cos(angle1) * radius,
          centerY + Math.sin(angle1) * radius
        );
        ctx.lineTo(
          centerX + Math.cos(angle1) * (radius - thickness),
          centerY + Math.sin(angle1) * (radius - thickness)
        );

        // Valley
        ctx.lineTo(
          centerX + Math.cos(angle2) * (radius - thickness),
          centerY + Math.sin(angle2) * (radius - thickness)
        );

        if (i < reedCount - 1) {
          ctx.lineTo(
            centerX + Math.cos(angle2) * radius,
            centerY + Math.sin(angle2) * radius
          );
        }
      }

      ctx.closePath();
    }

    function drawCoinFace(ctx, centerX, centerY, radius, faceType, rotationAngle = 0) {
      // Base metallic circle with gradient
      const gradient = ctx.createRadialGradient(
        centerX - radius * 0.3, centerY - radius * 0.3, radius * 0.1,
        centerX, centerY, radius
      );

      if (faceType === 'front') {
        gradient.addColorStop(0, '#ffd700'); // Highlight
        gradient.addColorStop(0.5, '#d4af37');
        gradient.addColorStop(1, '#b8962e'); // Shadow

        ctx.fillStyle = gradient;
        ctx.beginPath();
        ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
        ctx.fill();

        // Inner border
        ctx.strokeStyle = '#a08527';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.arc(centerX, centerY, radius - 15, 0, Math.PI * 2);
        ctx.stroke();

        // WastedToken Mint emblem (procedural)
        ctx.save();
        ctx.translate(centerX, centerY);
        ctx.rotate(rotationAngle);

        // Outer ring
        ctx.strokeStyle = '#ffd700';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.arc(0, 0, radius * 0.65, 0, Math.PI * 2);
        ctx.stroke();

        // WastedToken text (simplified)
        ctx.fillStyle = '#b8962e';
        ctx.font = `bold ${Math.floor(radius * 0.14)}px 'Courier New', monospace`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('WASTEDTOKEN', 0, -radius * 0.35);

        // Mint text
        ctx.font = `bold ${Math.floor(radius * 0.1)}px 'Courier New', monospace`;
        ctx.fillText('MINT', 0, radius * 0.15);

        // Central emblem (abstract token symbol)
        ctx.strokeStyle = '#ffd700';
        ctx.lineWidth = 2;
        const size = radius * 0.3;

        // Token shape
        ctx.beginPath();
        ctx.moveTo(0, -size);
        ctx.lineTo(size * 0.5, -size * 0.5);
        ctx.lineTo(size * 0.5, size * 0.5);
        ctx.lineTo(0, size);
        ctx.lineTo(-size * 0.5, size * 0.5);
        ctx.lineTo(-size * 0.5, -size * 0.5);
        ctx.closePath();
        ctx.stroke();

        // Inner details
        ctx.beginPath();
        ctx.moveTo(-size * 0.3, -size * 0.3);
        ctx.lineTo(size * 0.3, size * 0.3);
        ctx.moveTo(size * 0.3, -size * 0.3);
        ctx.lineTo(-size * 0.3, size * 0.3);
        ctx.stroke();

        // Small dots around the edge
        for (let i = 0; i < 8; i++) {
          const angle = (i / 8) * Math.PI * 2;
          const dotX = Math.cos(angle) * radius * 0.65;
          const dotY = Math.sin(angle) * radius * 0.65;

          ctx.fillStyle = '#ffd700';
          ctx.beginPath();
          ctx.arc(dotX, dotY, 3, 0, Math.PI * 2);
          ctx.fill();
        }

        ctx.restore();
      } else {
        // Back face
        gradient.addColorStop(0, '#c0c0c0');
        gradient.addColorStop(0.5, '#a8a8a8');
        gradient.addColorStop(1, '#909090');

        ctx.fillStyle = gradient;
        ctx.beginPath();
        ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
        ctx.fill();

        // Inner border
        ctx.strokeStyle = '#7a7a7a';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.arc(centerX, centerY, radius - 15, 0, Math.PI * 2);
        ctx.stroke();

        // Denomination text
        ctx.fillStyle = '#909090';
        ctx.font = `bold ${Math.floor(radius * 0.16)}px 'Courier New', monospace`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('10,000 TOKENS', centerX, centerY - radius * 0.2);

        // Token count symbol
        const size = radius * 0.35;
        ctx.strokeStyle = '#c0c0c0';
        ctx.lineWidth = 2;

        // Grid pattern
        for (let i = 0; i < 4; i++) {
          const x = centerX - size + (i * size / 1.5);

          ctx.beginPath();
          ctx.moveTo(x, centerY + size);
          ctx.lineTo(x, centerY - size);
          ctx.stroke();

          if (i < 3) {
            ctx.beginPath();
            ctx.moveTo(centerX - size, centerY + i * size / 1.5);
            ctx.lineTo(centerX + size, centerY + i * size / 1.5);
            ctx.stroke();
          }
        }

        // Small dots around the edge
        for (let i = 0; i < 8; i++) {
          const angle = (i / 8) * Math.PI * 2;
          const dotX = centerX + Math.cos(angle) * radius * 0.65;
          const dotY = centerY + Math.sin(angle) * radius * 0.65;

          ctx.fillStyle = '#c0c0c0';
          ctx.beginPath();
          ctx.arc(dotX, dotY, 3, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    }

    function drawCoin(ctx, centerX, centerY, radius, rotationAngle) {
      // Draw reeded edge (visible as coin rotates)
      const reedCount = 48;
      const edgeThickness = 15;

      // Create a gradient for the edge
      const edgeGradient = ctx.createLinearGradient(
        centerX - radius, centerY,
        centerX + radius, centerY
      );
      edgeGradient.addColorStop(0, '#b8962e');
      edgeGradient.addColorStop(0.25, '#ffd700');
      edgeGradient.addColorStop(0.5, '#d4af37');
      edgeGradient.addColorStop(0.75, '#ffd700');
      edgeGradient.addColorStop(1, '#b8962e');

      ctx.fillStyle = edgeGradient;
      drawReededEdge(ctx, centerX, centerY, radius, edgeThickness, reedCount);
      ctx.fill();

      // Draw coin faces
      const faceRadius = radius - edgeThickness;

      // Front face (WastedToken Mint)
      drawCoinFace(ctx, centerX, centerY, faceRadius, 'front', rotationAngle);

      // Back face (10,000 TOKENS) - slightly offset to show both sides during flip
      const backOffset = Math.sin(rotationAngle * 2) * 5;
      ctx.save();
      ctx.translate(0, backOffset);
      drawCoinFace(ctx, centerX, centerY, faceRadius, 'back', rotationAngle + Math.PI);
      ctx.restore();

      // Specular highlight that moves with rotation
      const highlightX = centerX + Math.cos(rotationAngle * 3) * radius * 0.7;
      const highlightY = centerY - Math.sin(rotationAngle * 3) * radius * 0.7;

      const highlightGradient = ctx.createRadialGradient(
        highlightX, highlightY, 5,
        highlightX, highlightY, radius * 0.8
      );
      highlightGradient.addColorStop(0, 'rgba(255, 255, 255, 0.7)');
      highlightGradient.addColorStop(0.3, 'rgba(255, 255, 255, 0.4)');
      highlightGradient.addColorStop(1, 'rgba(255, 255, 255, 0)');

      ctx.fillStyle = highlightGradient;
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
      ctx.fill();
    }

    function drawEditionCoin(ctx, centerX, centerY, radius, editionType) {
      // Base metallic circle with gradient
      const gradient = ctx.createRadialGradient(
        centerX - radius * 0.3, centerY - radius * 0.3, radius * 0.1,
        centerX, centerY, radius
      );

      let highlightColor;
      let midColor;
      let shadowColor;
      let borderColor;
      let textColor;

      switch (editionType) {
        case 'bronze':
          highlightColor = '#cd7f32';
          midColor = '#b06528';
          shadowColor = '#945120';
          borderColor = '#a0522d';
          textColor = '#a0522d';
          break;
        case 'silver':
          highlightColor = '#c0c0c0';
          midColor = '#a8a8a8';
          shadowColor = '#909090';
          borderColor = '#7a7a7a';
          textColor = '#7a7a7a';
          break;
        case 'gold':
          highlightColor = '#ffd700';
          midColor = '#d4af37';
          shadowColor = '#b8962e';
          borderColor = '#a08527';
          textColor = '#a08527';
          break;
        case 'black':
          highlightColor = '#1f1f1f';
          midColor = '#141414';
          shadowColor = '#0a0a0a';
          borderColor = '#333333';
          textColor = '#333333';
          break;
      }

      gradient.addColorStop(0, highlightColor);
      gradient.addColorStop(0.5, midColor);
      gradient.addColorStop(1, shadowColor);

      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
      ctx.fill();

      // Inner border
      ctx.strokeStyle = borderColor;
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius - 15, 0, Math.PI * 2);
      ctx.stroke();

      // Edition-specific details
      if (editionType === 'black') {
        // Obsidian effect with subtle patterns
        const patternSize = radius * 0.3;

        ctx.fillStyle = '#2a2a2a';
        for (let i = 0; i < 4; i++) {
          const angle = (i / 4) * Math.PI * 2;
          const x = centerX + Math.cos(angle) * patternSize;
          const y = centerY + Math.sin(angle) * patternSize;

          ctx.beginPath();
          ctx.arc(x, y, radius * 0.15, 0, Math.PI * 2);
          ctx.fill();
        }

        // "WastedToken" text
        ctx.fillStyle = '#3a3a3a';
        ctx.font = `bold ${Math.floor(radius * 0.14)}px 'Courier New', monospace`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('WASTEDTOKEN', centerX, centerY - radius * 0.25);

        // "MINT" text
        ctx.font = `bold ${Math.floor(radius * 0.1)}px 'Courier New', monospace`;
        ctx.fillText('MINT', centerX, centerY + radius * 0.15);
      } else {
        // Denomination for other editions
        ctx.fillStyle = textColor;
        ctx.font = `bold ${Math.floor(radius * 0.16)}px 'Courier New', monospace`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('10,000 TOKENS', centerX, centerY - radius * 0.2);

        // Token count symbol
        const size = radius * 0.35;
        ctx.strokeStyle = highlightColor;
        ctx.lineWidth = 2;

        // Grid pattern
        for (let i = 0; i < 4; i++) {
          const x = centerX - size + (i * size / 1.5);

          ctx.beginPath();
          ctx.moveTo(x, centerY + size);
          ctx.lineTo(x, centerY - size);
          ctx.stroke();

          if (i < 3) {
            ctx.beginPath();
            ctx.moveTo(centerX - size, centerY + i * size / 1.5);
            ctx.lineTo(centerX + size, centerY + i * size / 1.5);
            ctx.stroke();
          }
        }
      }

      // Small dots around the edge
      const dotCount = 8;
      for (let i = 0; i < dotCount; i++) {
        const angle = (i / dotCount) * Math.PI * 2;
        const dotX = centerX + Math.cos(angle) * radius * 0.65;
        const dotY = centerY + Math.sin(angle) * radius * 0.65;

        ctx.fillStyle = highlightColor;
        ctx.beginPath();
        ctx.arc(dotX, dotY, 3, 0, Math.PI * 2);
        ctx.fill();
      }

      // Specular highlight
      const highlightGradient = ctx.createRadialGradient(
        centerX - radius * 0.5, centerY - radius * 0.5, 10,
        centerX, centerY, radius
      );
      highlightGradient.addColorStop(0, 'rgba(255, 255, 255, 0.6)');
      highlightGradient.addColorStop(0.3, 'rgba(255, 255, 255, 0.3)');
      highlightGradient.addColorStop(1, 'rgba(255, 255, 255, 0)');

      ctx.fillStyle = highlightGradient;
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
      ctx.fill();
    }

    // Hero coin animation
    const heroCanvas = document.getElementById('coin-hero');
    const heroCtx = heroCanvas.getContext('2d');

    let heroAnimationId;
    let heroTime = 0;
    let isPaused = false;

    function renderHeroCoin() {
      if (isPaused) return;

      // Clear canvas
      heroCtx.clearRect(0, 0, heroCanvas.width, heroCanvas.height);

      const centerX = heroCanvas.width / 2;
      const centerY = heroCanvas.height / 2;
      const radius = Math.min(centerX, centerY) - 40;

      // Calculate rotation angle based on time
      heroTime += 0.015; // Animation speed
      if (heroTime > 1) heroTime = 0;

      const rotationAngle = heroTime * Math.PI * 2;

      drawCoin(heroCtx, centerX, centerY, radius, rotationAngle);

      heroAnimationId = requestAnimationFrame(renderHeroCoin);
    }

    window.demo.canvas = heroCanvas;
    window.demo.setTime = function(t) {
      isPaused = true;
      heroTime = t % 1; // Ensure t is in [0,1]
      renderHeroCoin();
    };
    window.demo.pause = function() {
      isPaused = true;
      cancelAnimationFrame(heroAnimationId);
    };

    // Start animation
    renderHeroCoin();

    // Edition coin rendering
    const editionCanvases = document.querySelectorAll('.edition-canvas');

    editionCanvases.forEach((canvas, index) => {
      const editionType = ['bronze', 'silver', 'gold', 'black'][index];

      // Set canvas size based on container
      const container = canvas.parentElement;
      const size = Math.min(container.clientWidth, container.clientHeight);
      canvas.width = size;
      canvas.height = size;

      const ctx = canvas.getContext('2d');
      const centerX = size / 2;
      const centerY = size / 2;
      const radius = (size / 2) - 30;

      drawEditionCoin(ctx, centerX, centerY, radius, editionType);
    });

    // Add to cart function
    window.addToCart = function(edition) {
      alert(`Added ${edition} Edition to your cart!`);
    };

    // Responsive canvas resizing for editions
    window.addEventListener('resize', () => {
      editionCanvases.forEach((canvas, index) => {
        const editionType = ['bronze', 'silver', 'gold', 'black'][index];

        const container = canvas.parentElement;
        const size = Math.min(container.clientWidth, container.clientHeight);
        canvas.width = size;
        canvas.height = size;

        const ctx = canvas.getContext('2d');
        const centerX = size / 2;
        const centerY = size / 2;
        const radius = (size / 2) - 30;

        drawEditionCoin(ctx, centerX, centerY, radius, editionType);
      });
    });

    // Pause animation on page unload
    window.addEventListener('beforeunload', () => {
      window.demo.pause();
    });
  </script>
</body>
